def separate_parentheses_groups(s: str) -> list[str]:
    """
    Splits a string containing multiple groups of balanced parentheses into a list of strings,
    each representing a separate top-level balanced group.

    For example, "(()())()((()))" returns ["(()())", "()", "((()))"].

    Assumes the input consists only of '(' and ')' and is a concatenation of balanced groups.
    Raises ValueError if the input is malformed.
    """
    groups = []
    depth = 0
    start = 0
    for i, ch in enumerate(s):
        if ch == '(':
            depth += 1
        elif ch == ')':
            depth -= 1
            if depth < 0:
                raise ValueError("Unbalanced parentheses: too many closing parentheses")
        else:
            raise ValueError(f"Invalid character '{ch}' encountered; expected only '(' and ')'")
        if depth == 0:
            groups.append(s[start:i+1])
            start = i+1
    if depth != 0:
        raise ValueError("Unbalanced parentheses: missing closing parentheses")
    return groups

